181→export function PostDetailScreen({route}: Props) {
182→  const {user, session} = useAuth();
183→  const {colors} = useTheme();
184→  const {journalId} = route.params;
185→  const token = session?.access_token ?? '';
186→  const [commentInput, setCommentInput] = useState('');
187→  const [repostCaption, setRepostCaption] = useState('');
188→  const [showRepost, setShowRepost] = useState(false);
189→  const [replyingTo, setReplyingTo] = useState<{id: string; userName: string} | null>(null);
190→  const [expandedReplies, setExpandedReplies] = useState<Set<string>>(new Set());
191→  const scrollViewRef = useRef<ScrollView>(null);
192→  const inputRef = useRef<TextInput>(null);
193→
194→  const handleReply = useCallback((commentId: string, userName: string) => {
195→    setReplyingTo({id: commentId, userName});
196→    setTimeout(() => {
197→      inputRef.current?.focus();
198→      scrollViewRef.current?.scrollToEnd({animated: true});
199→    }, 100);
200→  }, []);
201→
202→  const handleToggleReplies = useCallback((commentId: string) => {
203→    setExpandedReplies(prev => {
204→      const next = new Set(prev);
205→      if (next.has(commentId)) {
206→        next.delete(commentId);
207→      } else {
208→        next.add(commentId);
209→      }
210→      return next;
211→    });
212→  }, []);
213→
214→  const detailQuery = useQuery({
215→    queryKey: ['journal', journalId, user?.id],
216→    queryFn: () => mobileApi.getJournalById(journalId, user?.id),
217→  });
218→
219→  const commentsQuery = useQuery({
220→    queryKey: ['journal-comments', journalId],
221→    queryFn: () => socialApi.getComments(journalId, null, 20),
222→  });
223→
224→  const reactionMutation = useMutation({
225→    mutationFn: async (reactionType: string) => {
226→      const journal = detailQuery.data?.journal;
227→      const receiverId = journal?.user_id ?? journal?.users?.id;
228→      if (!token) throw new Error('Please log in to react.');
229→      if (!journal?.id || !receiverId) throw new Error('Missing journal data.');
230→      return socialApi.toggleReaction(token, {
231→        journalId: journal.id,
232→        receiverId,
233→        reactionType,
234→      });
235→    },
236→    onSuccess: () => {
237→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
238→      queryClient.invalidateQueries({queryKey: ['feed']});
239→    },
240→    onError: e => Alert.alert('Reaction failed', e instanceof Error ? e.message : 'Error'),
241→  });
242→
243→  const bookmarkMutation = useMutation({
244→    mutationFn: async () => {
245→      if (!token) throw new Error('Please log in to bookmark.');
246→      return socialApi.toggleBookmark(token, {journalId});
247→    },
248→    onSuccess: () => {
249→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
250→      queryClient.invalidateQueries({queryKey: ['feed']});
251→    },
252→    onError: e => Alert.alert('Bookmark failed', e instanceof Error ? e.message : 'Error'),
253→  });
254→
255→  const addCommentMutation = useMutation({
256→    mutationFn: async () => {
257→      const body = commentInput.trim();
258→      const receiverId = detailQuery.data?.journal?.user_id ?? detailQuery.data?.journal?.users?.id;
259→      if (!token) throw new Error('Please log in to comment.');
260→      if (!body) throw new Error('Comment cannot be empty.');
261→      if (!receiverId) throw new Error('Missing journal owner.');
262→      return socialApi.addComment(token, {
263→        comments: body,
264→        postId: journalId,
265→        receiverId,
266→        parentId: replyingTo?.id,
267→      });
268→    },
269→    onSuccess: () => {
270→      const parentId = replyingTo?.id;
271→      setCommentInput('');
272→      setReplyingTo(null);
273→      queryClient.invalidateQueries({queryKey: ['journal-comments', journalId]});
274→      queryClient.invalidateQueries({queryKey: ['journal', journalId]});
275→      if (parentId) {
276→        setExpandedReplies(prev => new Set(prev).add(parentId));
277→      }
278→    },
279→    onError: e => Alert.alert('Comment failed', e instanceof Error ? e.message : 'Error'),
280→  });
281→
282→  const repostMutation = useMutation({
283→    mutationFn: async () => {
284→      if (!token) throw new Error('Please log in to repost.');
285→      return socialApi.createRepost(token, {
286→        sourceJournalId: journalId,
287→        caption: repostCaption.trim() || undefined,
288→      });
289→    },
290→    onSuccess: () => {
291→      setRepostCaption('');
292→      setShowRepost(false);
293→      Alert.alert('Reposted', 'Post was reposted to your feed.');
294→      queryClient.invalidateQueries({queryKey: ['feed']});
295→    },
296→    onError: e => Alert.alert('Repost failed', e instanceof Error ? e.message : 'Error'),
297→  });
298→
299→  const journal = detailQuery.data?.journal;
300→  const likeCount = resolveCount(journal?.like_count, journal?.likes_count);
301→  const commentCount = resolveCount(journal?.comment_count, journal?.comments_count);
302→  const bookmarkCount = resolveCount(journal?.bookmark_count);
303→  const comments = commentsQuery.data?.comments ?? [];
304→  const bannerImage = useMemo(() => extractBannerImage(journal?.content), [journal?.content]);
305→
306→  if (detailQuery.isLoading) {
