355→            name={journal?.users?.name}
356→            size={36}
357→            badge={journal?.users?.badge as 'legend' | 'og' | undefined}
358→          />
359→          <View style={styles.authorInfo}>
360→            <View style={styles.authorNameRow}>
361→              <Text style={[styles.authorName, {color: colors.textPrimary}]}>
362→                {journal?.users?.name || 'Unknown author'}
363→              </Text>
364→              {journal?.users?.badge ? (
365→                <BadgeCheckIcon size={16} badge={journal.users.badge as 'legend' | 'og'} />
366→              ) : null}
367→            </View>
368→            <Text style={[styles.dateText, {color: colors.textMuted}]}>
369→              {formatRelativeDate(journal?.created_at)}
370→            </Text>
371→          </View>
372→        </View>
373→
374→        {/* Action bar */}
375→        <ActionBar
376→          likeCount={likeCount}
377→          commentCount={commentCount}
378→          bookmarkCount={bookmarkCount}
379→          isLiked={journal?.has_liked}
380→          isBookmarked={journal?.has_bookmarked}
381→          userReaction={journal?.user_reaction}
382→          onReact={type => reactionMutation.mutate(type)}
383→          onComment={() => {/* scroll to comments */}}
384→          onBookmark={() => bookmarkMutation.mutate()}
385→          onRepost={() => setShowRepost(!showRepost)}
386→        />
387→
388→        {/* Repost section */}
389→        {showRepost && (
390→          <View style={[styles.repostSection, {backgroundColor: colors.bgSecondary, borderColor: colors.borderLight}]}>
391→            <TextInput
392→              value={repostCaption}
393→              onChangeText={setRepostCaption}
394→              placeholder="Add an optional caption"
395→              placeholderTextColor={colors.textFaint}
396→              style={[styles.commentInput, {backgroundColor: colors.bgElevated, borderColor: colors.borderCard, color: colors.textPrimary}]}
397→              maxLength={280}
398→              multiline
399→            />
400→            <PrimaryButton
401→              label={repostMutation.isPending ? 'Reposting...' : 'Repost to feed'}
402→              onPress={() => repostMutation.mutate()}
403→              disabled={repostMutation.isPending}
404→            />
405→          </View>
406→        )}
407→
408→        {/* Divider */}
409→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
410→
411→        {/* Content body */}
412→        <LexicalRenderer content={journal?.content} />
413→
414→        {/* Related posts */}
415→        <RelatedPosts journalId={journalId} />
416→
417→        {/* Divider */}
418→        <View style={[styles.divider, {backgroundColor: colors.borderLight}]} />
419→
420→        {/* Comments section */}
421→        <Text style={[styles.sectionTitle, {color: colors.textHeading}]}>
422→          Comments ({commentCount})
423→        </Text>
424→
425→        {commentsQuery.isLoading ? (
426→          <View style={styles.commentLoading}>
427→            <ActivityIndicator color={colors.loaderColor} />
428→          </View>
429→        ) : comments.filter(c => !c.parent_id).length === 0 ? (
430→          <Text style={[styles.noComments, {color: colors.textMuted}]}>
431→            No comments yet. Be the first!
432→          </Text>
433→        ) : (
434→          comments
435→            .filter(c => !c.parent_id)
436→            .map(comment => (
437→              <CommentThread
438→                key={comment.id}
439→                comment={comment}
440→                postId={journalId}
441→                allComments={comments}
442→                isLoggedIn={!!token}
443→                onReply={handleReply}
444→                onToggleReplies={handleToggleReplies}
445→                expandedReplies={expandedReplies}
446→                colors={colors}
447→                depth={0}
448→              />
449→            ))
450→        )}
451→
452→        {/* Comment input */}
453→        {token ? (
454→          <View style={styles.commentInputRow}>
455→            {replyingTo && (
456→              <View style={[styles.replyBanner, {backgroundColor: colors.bgSecondary}]}>
457→                <Text style={[styles.replyBannerText, {color: colors.textPrimary}]}>
458→                  Replying to {replyingTo.userName}
459→                </Text>
460→                <Pressable onPress={() => setReplyingTo(null)} hitSlop={8}>
461→                  <XIcon size={16} color={colors.textMuted} />
462→                </Pressable>
463→              </View>
464→            )}
465→            <TextInput
466→              ref={inputRef}
467→              value={commentInput}
468→              onChangeText={setCommentInput}
469→              placeholder={replyingTo ? `Reply to ${replyingTo.userName}...` : 'Write a comment...'}
470→              placeholderTextColor={colors.textFaint}
471→              style={[
472→                styles.commentInput,
473→                {
474→                  backgroundColor: colors.bgSecondary,
475→                  borderColor: colors.borderCard,
476→                  color: colors.textPrimary,
477→                },
478→              ]}
479→              maxLength={200}
480→              multiline
481→            />
482→            <PrimaryButton
483→              label={addCommentMutation.isPending ? 'Posting...' : 'Post'}
484→              onPress={() => addCommentMutation.mutate()}
485→              disabled={commentInput.trim().length === 0 || addCommentMutation.isPending}
486→            />
487→          </View>
488→        ) : null}
489→
490→        <View style={styles.bottomSpacer} />
491→      </View>
492→    </ScrollView>
493→  );
494→}
